"""
api.py — Key Detection REST API
================================
MP3 yükle → key + BPM + Camelot al.

Başlatma:
  python src/api.py
  # veya
  venv/bin/uvicorn src.api:app --reload --port 8000

Endpoint:
  POST /predict          — MP3 dosyası yükle
  GET  /health           — Sağlık kontrolü
  GET  /docs             — Swagger UI (otomatik)
"""

import os
import sys
import tempfile

from fastapi import FastAPI, File, UploadFile, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
from typing import List

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from predict import predict

PROJECT_ROOT  = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
DEFAULT_MODEL = os.path.join(PROJECT_ROOT, "models", "key_detection_model.keras")

app = FastAPI(
    title="Key Detection API",
    description="MP3 dosyasından müzikal ton ve BPM tespiti",
    version="1.0.0",
)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_methods=["*"],
    allow_headers=["*"],
)


# ── Response modeli ───────────────────────────────────────────────────────────

class KeyCandidate(BaseModel):
    key:        str
    camelot:    str
    confidence: float


class PredictResponse(BaseModel):
    key:        str           # "A Minor"
    camelot:    str           # "8A"
    confidence: float         # 0.743
    bpm:        float         # 127.4
    top3:       List[KeyCandidate]


# ── Endpoints ─────────────────────────────────────────────────────────────────

@app.get("/", response_class=HTMLResponse)
def index():
    return HTML_UI


@app.get("/health")
def health():
    model_ok = os.path.exists(DEFAULT_MODEL)
    return {
        "status": "ok" if model_ok else "model_missing",
        "model":  DEFAULT_MODEL,
        "model_exists": model_ok,
    }


@app.post("/predict", response_model=PredictResponse)
async def predict_key(file: UploadFile = File(...)):
    # Sadece MP3/WAV kabul et
    if not file.filename or not file.filename.lower().endswith((".mp3", ".wav", ".m4a", ".flac")):
        raise HTTPException(status_code=400, detail="Sadece MP3, WAV, M4A veya FLAC dosyaları desteklenir.")

    # Geçici dosyaya kaydet
    suffix = os.path.splitext(file.filename)[1]
    with tempfile.NamedTemporaryFile(suffix=suffix, delete=False) as tmp:
        tmp.write(await file.read())
        tmp_path = tmp.name

    try:
        result = predict(tmp_path, model_path=DEFAULT_MODEL)
    except FileNotFoundError as e:
        raise HTTPException(status_code=503, detail=str(e))
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Analiz hatası: {e}")
    finally:
        os.unlink(tmp_path)

    return PredictResponse(
        key        = result["key"],
        camelot    = result["camelot"],
        confidence = round(result["confidence"], 4),
        bpm        = result["bpm"],
        top3       = [
            KeyCandidate(key=k, camelot=c, confidence=round(conf, 4))
            for k, c, conf in result["top3"]
        ],
    )


